{
  "prompt": "Create a stylized illustration of {character_name} from {franchise}.",

  "character_analysis": {
    "personality_archetype": "Derive core archetype (heroic, calm, mysterious, aggressive) based on canon portrayal",
    "signature_color": "Extract primary color from original design and use as main visual accent"
  },

  "pose_and_body_language": {
    "heroic": "dynamic action, wide stance, explosive movement",
    "calm_confident": "balanced relaxed posture, minimal motion",
    "dark_mysterious": "low stance, subtle movement, hidden or sharp gaze",
    "aggressive_intense": "forward-leaning attack stance, visible tension, clenched fists"
  },

  "facial_expression": "Match expression precisely to personality and emotional tone",

  "art_style": [
    "anime",
    "streetwear",
    "graphic poster hybrid",
    "clean lineart",
    "semi-flat shading",
    "high contrast",
    "modern minimal design"
