    "visual_flow": "strong diagonal composition",
    "depth": "layered depth for dynamic poster feel"
  },

  "outfit_design": {
    "style": "modern streetwear / techwear reinterpretation",
    "rule": "preserve recognizable identity elements of original character"
  },

  "color_palette": {
    "background": "clean white dominant background",
    "primary_accent": "signature character color",
    "secondary_accent": "complementary or analogous tone",
    "rule": "minimal, bold, high-contrast palette"
  },

  "background": {
    "type": "abstract geometric poster layout",
    "style": "negative space focused",
    "accents": "subtle integration of character color theme"
  },

  "effects": [
    "energy strokes",
    "paint lines",
    "motion accents aligned with character energy"
  ],

  "lighting": {
    "type": "sharp directional lighting",
    "shadows": "crisp shadows",
    "glow": "subtle signature color glow"
  },

  "rendering_quality": {
    "style": "ultra-clean vector finish",
    "output": "poster-quality composition",
    "resolution": "4K high detail"
  }
}

